const path = require('path');

const problemsFilePath = path.resolve(__dirname, '../../data/problems.json');

let problemsData = null;

function loadProblemsData() {
  if (!problemsData) {
    const raw = fs.readFileSync(problemsFilePath, 'utf-8');
    problemsData = JSON.parse(raw);
  }
  return problemsData;
}

/**
 * Get detailed problem info by problemId including component statistics
 * @param {string} problemId
 * @returns {object|null} problem detail with component stats or null if not found
 */
function getProblemDetailWithStats(problemId) {
  const problems = loadProblemsData();
  const problem = problems.find(p => String(p.id) === String(problemId));
  if (!problem) {
    return null;
  }

  // Aggregate component statistics
  // language counts, status counts, max points
  const languageCounts = {};
  const statusCounts = {};
  let maxPoints = 0;

  if (Array.isArray(problem.components)) {
    for (const comp of problem.components) {
      // language count
      if (comp.language) {
        languageCounts[comp.language] = (languageCounts[comp.language] || 0) + 1;
      }
      // status count
      if (comp.status) {
        statusCounts[comp.status] = (statusCounts[comp.status] || 0) + 1;
      }
      // max points
      if (typeof comp.points === 'number' && comp.points > maxPoints) {
        maxPoints = comp.points;
      }
    }
  }

  return {
    ...problem,
    componentStats: {
      languageCounts,
      statusCounts,
      maxPoints
    }
  };
}

module.exports = {
  getProblemDetailWithStats
};
