/**
 * GET /api/v1/problems/:problemId
 * Returns problem detail with component statistics or 404 if not found
 */
async function getProblemDetail(req, res) {
  const problemId = req.params.problemId;
  const problemDetail = ProblemsService.getProblemDetailWithStats(problemId);

  if (!problemDetail) {
    return res.status(404).json({ error: 'Problem not found' });
  }

  return res.json(problemDetail);
}

module.exports = {
  getProblemDetail
};
